fn setup_backups_restore_previous_absence() {
    let repo = repo();
    json_output(
        bin()
            .args(["--json", "--repo-root"])
            .arg(repo.path())
            .args(["setup", "install"]),
    );
    let backups = json_output(
        bin()
            .args(["--json", "--repo-root"])
            .arg(repo.path())
