652	fn fnv1a64(bytes: &[u8]) -> u64 {
653	    let mut hash = 0xcbf29ce484222325;
654	    for byte in bytes {
655	        hash ^= u64::from(*byte);
656	        hash = hash.wrapping_mul(0x100000001b3);
657	    }
658	    hash
