275	fn materialize_bundle(repo: &Path, plan: &mut SetupPlan, dry_run: bool) -> Result<()> {
276	    let guidance = workspace::setup_target(repo, catalog::BUNDLE_GUIDANCE)?;
277	    let marker = workspace::setup_target(repo, catalog::BUNDLE_MARKER)?;
278	    let marker_data = workspace::read_bundle_marker(&marker)?;
279	    if marker_data
280	        .as_ref()
281	        .is_some_and(|marker| !catalog::is_managed_bundle_marker(marker))
282	    {
283	        return Err(Codex1Error::SetupBundle(
284	            "invalid Codex1 setup bundle marker".into(),
285	        ));
286	    }
287	
288	    for relative in catalog::managed_skill_files() {
289	        let skill = workspace::setup_target(repo, relative)?;
290	        workspace::ensure_owned_file_writable(
291	            &skill,
292	            &catalog::expected_current_body(relative)?,
293	            catalog::marker_allows_file_repair(marker_data.as_ref(), relative),
294	        )?;
295	    }
296	    for relative in catalog::managed_supporting_doc_files() {
297	        let doc = workspace::setup_target(repo, relative)?;
298	        workspace::ensure_owned_file_writable(
299	            &doc,
300	            &catalog::expected_current_body(relative)?,
301	            catalog::marker_allows_file_repair(marker_data.as_ref(), relative),
302	        )?;
303	    }
304	
305	    for relative in catalog::managed_skill_files() {
306	        let skill = workspace::setup_target(repo, relative)?;
307	        workspace::write_owned_file(
308	            repo,
309	            &skill,
310	            &catalog::expected_current_body(relative)?,
311	            catalog::marker_allows_file_repair(marker_data.as_ref(), relative),
312	            "managed skill",
313	            plan,
314	            dry_run,
315	        )?;
316	    }
317	    for relative in catalog::managed_supporting_doc_files() {
318	        let doc = workspace::setup_target(repo, relative)?;
319	        workspace::write_owned_file(
320	            repo,
321	            &doc,
322	            &catalog::expected_current_body(relative)?,
323	            catalog::marker_allows_file_repair(marker_data.as_ref(), relative),
324	            "managed supporting doc",
325	            plan,
326	            dry_run,
327	        )?;
328	    }
329	    remove_legacy_bundle_files_not_current(repo, marker_data.as_ref(), plan, dry_run)?;
330	    workspace::write_guidance_file(repo, &guidance, plan, dry_run)?;
331	    workspace::write_owned_file(
332	        repo,
333	        &marker,
334	        &catalog::bundle_marker_body(),
335	        marker_data
336	            .as_ref()
337	            .is_some_and(catalog::is_managed_bundle_marker),
338	        "bundle marker",
339	        plan,
340	        dry_run,
341	    )?;
342	    Ok(())
343	}
