345	fn remove_legacy_bundle_files_not_current(
346	    repo: &Path,
347	    marker: Option<&catalog::BundleMarker>,
348	    plan: &mut SetupPlan,
349	    dry_run: bool,
350	) -> Result<()> {
351	    let Some(marker) = marker.filter(|marker| catalog::is_managed_bundle_marker(marker)) else {
352	        return Ok(());
353	    };
354	    for relative in &marker.files {
355	        if catalog::is_current_bundle_file(relative) || relative == catalog::BUNDLE_GUIDANCE {
356	            continue;
357	        }
358	        let path = workspace::setup_target(repo, relative)?;
359	        match fs::read_to_string(&path) {
360	            Ok(text) if catalog::is_managed_restore_body(relative, &text) => {
361	                workspace::remove_file_with_backup(
362	                    repo,
363	                    &path,
364	                    "remove legacy managed setup file",
365	                    plan,
366	                    dry_run,
367	                )?
368	            }
369	            Ok(_) => {}
370	            Err(error) if error.kind() == ErrorKind::NotFound => {}
371	            Err(error) => {
372	                return Err(Codex1Error::SetupBundle(format!(
373	                    "failed to read {}: {error}",
374	                    path.display()
375	                )))
376	            }
377	        }
378	    }
379	    Ok(())
380	}
