382	fn remove_bundle(repo: &Path, plan: &mut SetupPlan, dry_run: bool) -> Result<()> {
383	    let marker = workspace::setup_target(repo, catalog::BUNDLE_MARKER)?;
384	    let (files, strict) = match workspace::read_bundle_marker(&marker)? {
385	        Some(marker_data) => {
386	            if !catalog::is_managed_bundle_marker(&marker_data) {
387	                return Err(Codex1Error::SetupBundle(
388	                    "invalid Codex1 setup bundle marker".into(),
389	                ));
390	            }
391	            (marker_data.files, true)
392	        }
393	        None => (catalog::current_bundle_files(), false),
394	    };
395	    for relative in files {
396	        let path = workspace::setup_target(repo, &relative)?;
397	        if relative == catalog::BUNDLE_GUIDANCE {
398	            workspace::remove_guidance_if_owned(repo, &path, strict, plan, dry_run)?;
399	        } else {
400	            workspace::remove_owned_file_if_managed(repo, &path, &relative, strict, plan, dry_run)?;
401	        }
402	    }
403	    workspace::remove_bundle_marker_file(repo, &marker, plan, dry_run)?;
404	    Ok(())
405	}
