407	fn marker_state(repo: &Path) -> SetupFileState {
408	    let Ok(path) = workspace::setup_target(repo, catalog::BUNDLE_MARKER) else {
409	        return SetupFileState::Invalid;
410	    };
411	    match workspace::read_bundle_marker(&path) {
412	        Ok(Some(marker)) if catalog::is_current_marker(&marker) => SetupFileState::Current,
413	        Ok(Some(marker)) if catalog::is_managed_bundle_marker(&marker) => SetupFileState::Stale,
414	        Ok(Some(_)) => SetupFileState::Invalid,
415	        Ok(None) => SetupFileState::Missing,
416	        Err(_) => SetupFileState::Invalid,
417	    }
418	}
