420	fn owned_file_state(repo: &Path, relative: &str) -> SetupFileState {
421	    let Ok(path) = workspace::setup_target(repo, relative) else {
422	        return SetupFileState::Invalid;
423	    };
424	    let Some(expected) = catalog::expected_body(relative) else {
425	        return SetupFileState::Invalid;
426	    };
427	    match fs::read_to_string(&path) {
428	        Ok(text) if text == expected => SetupFileState::Current,
429	        Ok(_) => SetupFileState::Stale,
430	        Err(error) if error.kind() == ErrorKind::NotFound => SetupFileState::Missing,
431	        Err(_) => SetupFileState::Invalid,
432	    }
433	}
