435	fn guidance_state(repo: &Path) -> SetupFileState {
436	    let Ok(path) = workspace::setup_target(repo, catalog::BUNDLE_GUIDANCE) else {
437	        return SetupFileState::Invalid;
438	    };
439	    match fs::read_to_string(&path) {
440	        Ok(text) if text == guidance::body() || text.contains(&guidance::managed_block()) => {
441	            SetupFileState::Current
442	        }
443	        Ok(text) if guidance::has_managed_block(&text) => SetupFileState::Stale,
444	        Ok(_) => SetupFileState::Missing,
445	        Err(error) if error.kind() == ErrorKind::NotFound => SetupFileState::Missing,
446	        Err(_) => SetupFileState::Invalid,
447	    }
448	}
